from collections import deque

def is_connected(graph):
    if not graph:
        return True

    nodes = set(graph.keys())

    # If the graph has no nodes (e.g., an empty dictionary)
    if not nodes:
        return True

    # Pick an arbitrary starting node
    start_node = next(iter(nodes))

    visited = set()
    queue = deque([start_node])
    visited.add(start_node)

    while queue:
        current_node = queue.popleft()

        # Iterate through neighbors. The graph is treated as undirected
        # or checking for weak connectivity if it's directed.
        for neighbor in graph[current_node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)

    # The graph is connected if all nodes are visited
    return len(visited) == len(nodes)
